namespace NotificationApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;

    // Simulates an initial batch from a database or API.
    private readonly List<Notification> _all =
    [
        new(1, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-30)),
        new(2, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-15)),
        new(3, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-5)),
    ];

    private static readonly string[] Templates =
    [
        "Server health check passed.",
        "A new user signed up.",
        "Deployment completed successfully.",
        "Disk usage exceeded 80%.",
        "Backup finished.",
        "New comment on your post.",
    ];

    /// <summary>Returns all notifications available right now.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
        => Task.FromResult(_all.OrderByDescending(n => n.Timestamp).ToList());

    /// <summary>Returns only notifications newer than <paramref name="since"/>.</summary>
    public Task<List<Notification>> GetNewNotificationsSinceAsync(DateTime since)
    {
        // Randomly produce 0-1 new notifications each poll to simulate activity.
        if (Random.Shared.Next(3) == 0)
        {
            var id = Interlocked.Increment(ref _nextId);
            var msg = Templates[Random.Shared.Next(Templates.Length)];
            _all.Add(new Notification(id, msg, DateTime.UtcNow));
        }

        var newer = _all.Where(n => n.Timestamp > since)
                        .OrderByDescending(n => n.Timestamp)
                        .ToList();
        return Task.FromResult(newer);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationApp.Services.NotificationService Svc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (Items is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@Items.Count</span>
    }
</h1>

@if (Items is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (Items.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in Items)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    [PersistentState]
    public List<Notification>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch when state was NOT restored from prerender.
        Items ??= await Svc.GetNotificationsAsync();
        _lastCheck = Items.Count > 0
            ? Items.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is never called during prerender — safe to start polling.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
                var newer = await Svc.GetNewNotificationsSinceAsync(_lastCheck);
                if (newer.Count > 0)
                {
                    Items = newer.Concat(Items!).ToList();
                    _lastCheck = Items.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

